import sys


class StepLimitExceeded(Exception):
    """Raised when executed code exceeds the allowed number of instructions."""
    pass


DEFAULT_STEP_LIMIT = 1_000_000


def execute_limited(code_string, step_limit=DEFAULT_STEP_LIMIT, globals_dict=None, locals_dict=None):
    """Execute arbitrary Python code with a global step limit using sys.settrace.

    Raises StepLimitExceeded if the number of traced events exceeds step_limit.
    """
    if globals_dict is None:
        globals_dict = {}
    if locals_dict is None:
        locals_dict = {}

    state = {'count': 0}

    def tracer(frame, event, arg):
        state['count'] += 1
        if state['count'] > step_limit:
            raise StepLimitExceeded(
                f"Execution exceeded step limit of {step_limit} instructions"
            )
        return tracer

    previous_trace = sys.gettrace()
    sys.settrace(tracer)
    try:
        exec(code_string, globals_dict, locals_dict)
    finally:
        sys.settrace(previous_trace)

    return globals_dict, locals_dict

from simulator import execute_limited, StepLimitExceeded, DEFAULT_STEP_LIMIT


def will_halt(program_code, program_input, step_limit=DEFAULT_STEP_LIMIT):
    '''Attempt to decide if program_code halts given program_input.

    Runs the program inside a step-limited simulator. Returns True if the
    program terminates (normally or via an exception) within the step limit,
    and False if it exceeds the step limit (assumed to run forever).
    '''
    globals_dict = {'program_input': program_input}
    locals_dict = {}
    try:
        execute_limited(program_code, step_limit=step_limit,
                        globals_dict=globals_dict, locals_dict=locals_dict)
        return True
    except StepLimitExceeded:
        return False
    except Exception:
        # Any other exception means the program terminated (halted).
        return True
